CREATE TABLE IF NOT EXISTS users (
    id SERIAL PRIMARY KEY,
    name VARCHAR(120),
    goal VARCHAR(80) DEFAULT 'viagem',
    level_name VARCHAR(80) DEFAULT 'iniciante',
    xp INTEGER DEFAULT 0,
    app_level INTEGER DEFAULT 1,
    hearts INTEGER DEFAULT 5,
    streak INTEGER DEFAULT 1,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS course_units (
    id SERIAL PRIMARY KEY,
    level_code VARCHAR(10) NOT NULL,
    title VARCHAR(160) NOT NULL,
    theme VARCHAR(160),
    grammar TEXT,
    items JSONB DEFAULT '[]'::jsonb,
    position INTEGER DEFAULT 0,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS vocabulary (
    id SERIAL PRIMARY KEY,
    russian TEXT NOT NULL,
    portuguese TEXT NOT NULL,
    pronunciation TEXT,
    category VARCHAR(80),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS phrases (
    id SERIAL PRIMARY KEY,
    russian TEXT NOT NULL,
    portuguese TEXT NOT NULL,
    pronunciation TEXT,
    category VARCHAR(80),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS review_items (
    id SERIAL PRIMARY KEY,
    user_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
    russian TEXT NOT NULL,
    portuguese TEXT,
    pronunciation TEXT,
    reason TEXT,
    count INTEGER DEFAULT 1,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS exam_results (
    id SERIAL PRIMARY KEY,
    user_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
    level_code VARCHAR(10),
    score INTEGER DEFAULT 0,
    total INTEGER DEFAULT 0,
    answers JSONB DEFAULT '[]'::jsonb,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS notes (
    id SERIAL PRIMARY KEY,
    user_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
    title VARCHAR(160) NOT NULL,
    body TEXT NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);


CREATE TABLE IF NOT EXISTS v10_expanded_lessons (
    id SERIAL PRIMARY KEY,
    code VARCHAR(80) UNIQUE NOT NULL,
    level_code VARCHAR(10) NOT NULL,
    theme VARCHAR(120) NOT NULL,
    russian TEXT NOT NULL,
    portuguese TEXT NOT NULL,
    pronunciation TEXT NOT NULL,
    explanation TEXT NOT NULL,
    questions JSONB DEFAULT '[]'::jsonb,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS v10_microphone_attempts (
    id SERIAL PRIMARY KEY,
    user_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
    expected_text TEXT NOT NULL,
    spoken_text TEXT,
    score INTEGER DEFAULT 0,
    feedback TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS v10_writing_tasks (
    id SERIAL PRIMARY KEY,
    user_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
    prompt TEXT NOT NULL,
    expected_text TEXT,
    user_text TEXT,
    feedback TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);
