INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("A1", "Sauda\u00e7\u00f5es", "Primeiras conversas", "Nesta unidade A1, voc\u00ea aprende primeiras conversas com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Как дела?", "Меня зовут Анна.", "Я из Бразилии.", "Очень приятно.", "Я учу русский язык."]'::jsonb, 1);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("A1", "Apresenta\u00e7\u00e3o", "Nome e origem", "Nesta unidade A1, voc\u00ea aprende nome e origem com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Очень приятно.", "Я учу русский язык.", "Я немного говорю по-русски.", "Я не понимаю.", "Повторите, пожалуйста."]'::jsonb, 2);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("A1", "Viagem b\u00e1sica", "Metr\u00f4, hotel e ajuda", "Nesta unidade A1, voc\u00ea aprende metr\u00f4, hotel e ajuda com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Я не понимаю.", "Повторите, пожалуйста.", "Говорите медленнее, пожалуйста.", "Где метро?", "Где гостиница?"]'::jsonb, 3);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("A1", "Comida b\u00e1sica", "\u00c1gua, ch\u00e1 e restaurante", "Nesta unidade A1, voc\u00ea aprende \u00e1gua, ch\u00e1 e restaurante com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Где метро?", "Где гостиница?", "Сколько это стоит?", "Мне нужна помощь.", "Я хочу воды."]'::jsonb, 4);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("A2", "Rotina", "Dia a dia", "Nesta unidade A2, voc\u00ea aprende dia a dia com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Мне нужна помощь.", "Я хочу воды.", "Можно меню?", "Мне нравится русская музыка.", "Я люблю русские фильмы."]'::jsonb, 5);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("A2", "Cidade", "Lugares e dire\u00e7\u00e3o", "Nesta unidade A2, voc\u00ea aprende lugares e dire\u00e7\u00e3o com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Мне нравится русская музыка.", "Я люблю русские фильмы.", "Я хочу посетить музей.", "Парк очень красивый.", "Река рядом с городом."]'::jsonb, 6);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("A2", "Fam\u00edlia e pessoas", "Pessoas importantes", "Nesta unidade A2, voc\u00ea aprende pessoas importantes com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Парк очень красивый.", "Река рядом с городом.", "Сегодня холодно.", "Завтра будет тепло.", "Я готов к уроку."]'::jsonb, 7);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("A2", "Estudo", "Frases para aprender", "Nesta unidade A2, voc\u00ea aprende frases para aprender com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Завтра будет тепло.", "Я готов к уроку.", "Мне нужно повторить.", "Я хочу сдать экзамен.", "Это мой первый урок."]'::jsonb, 8);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("B1", "Opini\u00f5es", "Gostos e prefer\u00eancias", "Nesta unidade B1, voc\u00ea aprende gostos e prefer\u00eancias com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Я хочу сдать экзамен.", "Это мой первый урок.", "Я пишу по-русски.", "Я слушаю и повторяю.", "Я говорю медленно."]'::jsonb, 9);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("B1", "Cultura", "M\u00fasica, filme e museu", "Nesta unidade B1, voc\u00ea aprende m\u00fasica, filme e museu com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Я слушаю и повторяю.", "Я говорю медленно.", "Это полезная фраза.", "Я хочу узнать больше о России.", "Русская кухня очень интересная."]'::jsonb, 10);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("B1", "Trabalho", "Rotina profissional", "Nesta unidade B1, voc\u00ea aprende rotina profissional com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Я хочу узнать больше о России.", "Русская кухня очень интересная.", "Борщ — известный суп.", "Чай важен в русской культуре.", "Москва — столица России."]'::jsonb, 11);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("B1", "Provas", "Como revisar", "Nesta unidade B1, voc\u00ea aprende como revisar com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Чай важен в русской культуре.", "Москва — столица России.", "Санкт-Петербург известен музеями.", "Матрешка — традиционная кукла.", "Баба-яга живёт в сказках."]'::jsonb, 12);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("B2", "Hist\u00f3ria", "R\u00fassia em contexto", "Nesta unidade B2, voc\u00ea aprende r\u00fassia em contexto com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Матрешка — традиционная кукла.", "Баба-яга живёт в сказках.", "Я читаю русскую книгу.", "Мне нравится этот город.", "Я работаю сегодня."]'::jsonb, 13);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("B2", "Folclore", "Contos e s\u00edmbolos", "Nesta unidade B2, voc\u00ea aprende contos e s\u00edmbolos com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Мне нравится этот город.", "Я работаю сегодня.", "Мы идём в парк.", "Они живут в Москве.", "Я хочу чай без сахара."]'::jsonb, 14);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("B2", "Culin\u00e1ria", "Receitas e ingredientes", "Nesta unidade B2, voc\u00ea aprende receitas e ingredientes com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Они живут в Москве.", "Я хочу чай без сахара.", "У меня есть вопрос.", "Можно говорить по-русски?", "Я понимаю эту фразу."]'::jsonb, 15);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("B2", "Conversas longas", "Explicar ideias", "Nesta unidade B2, voc\u00ea aprende explicar ideias com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Можно говорить по-русски?", "Я понимаю эту фразу.", "Мне трудно, но интересно.", "Я хочу практиковаться каждый день.", "Я учу русский."]'::jsonb, 16);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("C1", "Leitura avan\u00e7ada", "Textos curtos", "Nesta unidade C1, voc\u00ea aprende textos curtos com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Я хочу практиковаться каждый день.", "Я учу русский.", "Я слушаю музыку.", "Я читаю книгу.", "Я пишу текст."]'::jsonb, 17);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("C1", "Gram\u00e1tica aplicada", "Casos em contexto", "Nesta unidade C1, voc\u00ea aprende casos em contexto com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Я читаю книгу.", "Я пишу текст.", "Я иду в музей.", "Я иду в парк.", "Я пью чай."]'::jsonb, 18);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("C1", "Argumenta\u00e7\u00e3o", "Opini\u00e3o e motivo", "Nesta unidade C1, voc\u00ea aprende opini\u00e3o e motivo com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Я иду в парк.", "Я пью чай.", "Мы учу русский.", "Мы слушаю музыку.", "Мы читаю книгу."]'::jsonb, 19);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("C1", "Cultura avan\u00e7ada", "Literatura e arte", "Nesta unidade C1, voc\u00ea aprende literatura e arte com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Мы слушаю музыку.", "Мы читаю книгу.", "Мы пишу текст.", "Мы иду в музей.", "Мы иду в парк."]'::jsonb, 20);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("C2", "Flu\u00eancia", "Naturalidade", "Nesta unidade C2, voc\u00ea aprende naturalidade com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Мы иду в музей.", "Мы иду в парк.", "Мы пью чай.", "Мы говорю медленно.", "Он учу русский."]'::jsonb, 21);
