INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("C2", "Produ\u00e7\u00e3o de texto", "Escrever melhor", "Nesta unidade C2, voc\u00ea aprende escrever melhor com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Он читаю книгу.", "Он пишу текст.", "Он иду в музей.", "Он иду в парк.", "Он пью чай."]'::jsonb, 23);
INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES ("C2", "Fala avan\u00e7ada", "Responder com confian\u00e7a", "Nesta unidade C2, voc\u00ea aprende responder com confian\u00e7a com som, tradu\u00e7\u00e3o, pron\u00fancia, explica\u00e7\u00e3o, escrita e perguntas.", '["Он иду в парк.", "Он пью чай.", "Он говорю медленно.", "Она учу русский.", "Она слушаю музыку."]'::jsonb, 24);
